/// Helper to safely deinit transformed ASTs while preserving PROGRAM_AST
fn maybeDeinitAst(source_ast: *const Program) void {
    if (source_ast == &PROGRAM_AST) {
        // This is the const PROGRAM_AST - don't deinit
        return;
    }
    // Heap-allocated transformed AST - safe to deinit
    var mutable_ast = @constCast(source_ast);
    mutable_ast.deinit();
}


/// Compiler Environment - Query compilation context at backend comptime
const CompilerEnv = struct {
    /// Check if a compiler flag is set
    pub fn hasFlag(comptime name: []const u8) bool {
        _ = name;
        return false;
    }

    /// Get environment variable value
    pub fn getEnv(comptime key: []const u8) ?[]const u8 {
        _ = key;
        return null;
    }
};

// Metacircular Code Generator

const std = @import("std");
const fusion_optimizer = @import("fusion_optimizer.zig");
const ast_functional = @import("ast_functional");

const BuildRequirement = struct {
    module_name: []const u8,
    source_code: []const u8,
};

const compiler_passes_collect_build_requires = struct {
    pub const Input = struct { program_ast: *const Program };
    pub const Output = union(enum) { collected: struct { ast: *const Program, requires: []BuildRequirement } };
    pub fn handler(__koru_event_input: Input) !Output {
        const program_ast = __koru_event_input.program_ast;

    // Walk AST to find all build:requires invocations and extract Source parameters
    // Note: using 'program_ast' instead of 'ast' to avoid shadowing the ast module import

    // For now, use a fixed-size array since ArrayList has API issues in Zig 0.15
    // TODO: Switch to ArrayList once we sort out the API
    var temp_array: [64]BuildRequirement = undefined;
    var count: usize = 0;

    std.debug.print("DEBUG collect_build_requires: Walking {d} items\n", .{program_ast.items.len});
    var flow_count: usize = 0;
    for (program_ast.items) |item| {
        switch (item) {
            .flow => |flow| {
                flow_count += 1;
                // Check if this is a build:requires invocation
                const inv = flow.invocation;
                std.debug.print("DEBUG: Flow #{d}: module_qualifier={s}, segments[0]={s}\n", .{
                    flow_count,
                    if (inv.path.module_qualifier) |mq| mq else "(none)",
                    if (inv.path.segments.len > 0) inv.path.segments[0] else "(empty)"
                });
                if (inv.path.module_qualifier) |mq| {
                    if (std.mem.eql(u8, mq, "build") and
                        inv.path.segments.len == 1 and
                        std.mem.eql(u8, inv.path.segments[0], "requires")) {

                        // Found build:requires! Extract the Source parameter
                        std.debug.print("DEBUG: ✓ Found build:requires invocation with {d} args\n", .{inv.args.len});
                        for (inv.args) |arg| {
                            std.debug.print("DEBUG: arg name='{s}'\n", .{arg.name});
                            if (std.mem.eql(u8, arg.name, "source")) {
                                // arg.value contains the raw source text
                                std.debug.print("DEBUG: Collecting requirement: {s}\n", .{arg.value});
                                if (count < temp_array.len) {
                                    temp_array[count] = BuildRequirement{
                                        .module_name = flow.module,
                                        .source_code = arg.value,
                                    };
                                    count += 1;
                                }
                            }
                        }
                    }
                }
            },
            else => {},
        }
    }

    const requires_slice = temp_array[0..count];
    return .{ .collected = .{ .ast = program_ast, .requires = requires_slice } };
    }
};

const compiler_emit_zig = struct {
    pub const Input = struct { ast: *const Program, allocator: std.mem.Allocator };
    pub const Output = union(enum) { emitted: struct { code: []const u8 } };
    pub fn handler(__koru_event_input: Input) !Output {

    // NEW VISITOR-BASED IMPLEMENTATION!
    // Replaces the 2184-line procedural emitter with visitor orchestrator

    // Import libraries needed for emission
    const emitter_lib = @import("emitter_helpers");
    const visitor_emitter_lib = @import("visitor_emitter.zig");
    const tap_registry_module = @import("tap_registry.zig");

    const MAX_SIZE = 256 * 1024; // 256KB buffer
    // CRITICAL: Buffer must be heap-allocated because we return a slice to it!
    // Stack-allocated buffers become invalid when function returns
    const buffer = try __koru_event_input.allocator.alloc(u8, MAX_SIZE);
    // Note: We don't defer free because the returned slice points to this memory

    // Create CodeEmitter
    var code_emitter = emitter_lib.CodeEmitter.init(buffer);

    // DEBUG: Check buffer state after init
    std.debug.print("\n[BUFFER DEBUG] After CodeEmitter.init:\n", .{});
    std.debug.print("[BUFFER DEBUG]   code_emitter.pos = {d}\n", .{code_emitter.pos});
    std.debug.print("[BUFFER DEBUG]   First 50 bytes: ", .{});
    for (buffer[0..@min(50, buffer.len)]) |byte| {
        if (byte >= 32 and byte < 127) {
            std.debug.print("{c}", .{byte});
        } else {
            std.debug.print("[{d}]", .{byte});
        }
    }
    std.debug.print("\n", .{});

    // Build tap registry (backend compiler pass)
    var tap_registry = tap_registry_module.buildTapRegistry(
        __koru_event_input.ast.items,
        __koru_event_input.allocator
    ) catch unreachable;
    defer tap_registry.deinit();

    // Build type registry from canonicalized AST
    var type_registry = type_registry_module.TypeRegistry.init(__koru_event_input.allocator);
    defer type_registry.deinit();
    type_registry.populateFromAST(__koru_event_input.ast.items) catch unreachable;

    // Create visitor orchestrator with tap registry and type registry
    var visitor_emitter = visitor_emitter_lib.VisitorEmitter.init(
        __koru_event_input.allocator,
        &code_emitter,
        __koru_event_input.ast.items,
        &tap_registry,
        &type_registry,
        .runtime_only
    );

    // Emit using visitor pattern!
    visitor_emitter.emit(__koru_event_input.ast) catch unreachable;

    // DEBUG: Check buffer after emission
    std.debug.print("\n[BUFFER DEBUG] After visitor_emitter.emit:\n", .{});
    std.debug.print("[BUFFER DEBUG]   code_emitter.pos = {d}\n", .{code_emitter.pos});
    std.debug.print("[BUFFER DEBUG]   First 50 bytes of buffer: ", .{});
    for (buffer[0..@min(50, buffer.len)]) |byte| {
        if (byte >= 32 and byte < 127) {
            std.debug.print("{c}", .{byte});
        } else {
            std.debug.print("[{d}]", .{byte});
        }
    }
    std.debug.print("\n", .{});

    // Get the emitted code
    const final_code = code_emitter.getOutput();

    std.debug.print("[BUFFER DEBUG] final_code length = {d}\n", .{final_code.len});
    std.debug.print("[BUFFER DEBUG]   First 50 bytes of final_code: ", .{});
    for (final_code[0..@min(50, final_code.len)]) |byte| {
        if (byte >= 32 and byte < 127) {
            std.debug.print("{c}", .{byte});
        } else {
            std.debug.print("[{d}]", .{byte});
        }
    }
    std.debug.print("\n\n", .{});

    return .{ .emitted = .{ .code = final_code } };
    }
};

const compiler_parse = struct {
    pub const Input = struct { source: []const u8, module_name: []const u8 };
    pub const Output = union(enum) { parsed: struct { items: []Item }, failed: struct { message: []const u8 } };
    pub fn handler(__koru_event_input: Input) Output {

    const Parser = @import("parser").Parser;
    // Note: 'std' is already imported at top level by the emitter

    // Use a comptime-friendly allocator
    // Note: In actual comptime context, we'd use a fixed buffer allocator
    // For now, we use the standard allocator which works at comptime
    var buffer: [1024 * 1024]u8 = undefined; // 1MB buffer for parsing
    var fba = std.heap.FixedBufferAllocator.init(&buffer);
    const allocator = fba.allocator();

    // Initialize parser
    var parser = Parser.init(allocator, __koru_event_input.source, __koru_event_input.module_name) catch {
        return .{ .failed = .{ .message = "Failed to initialize parser" } };
    };
    defer parser.deinit();

    // Parse the source
    const parse_result = parser.parse() catch {
        // Try to get error details if available
        if (parser.reporter.hasErrors()) {
            return .{ .failed = .{ .message = "Parse error - see compiler output" } };
        }
        return .{ .failed = .{ .message = "Failed to parse source" } };
    };

    // Return the parsed items
    // Note: The items are allocated in our buffer, which is stack-allocated
    // This is fine for comptime usage where everything gets evaluated away
    return .{ .parsed = .{ .items = parse_result.source_file.items } };
    }
};

const compiler_passes_evaluate_comptime = struct {
    pub const Input = struct { ast: *const Program, allocator: std.mem.Allocator };
    pub const Output = union(enum) { evaluated: struct { ast: *const Program, events_executed: usize } };
    pub fn handler(__koru_event_input: Input) !Output {
        const allocator = __koru_event_input.allocator;

    // Phase 1: Build map of comptime-only events
    // (Events that have FlowAST, ProgramAST, or Source parameters)
    var comptime_events: [64][]const u8 = undefined;
    var comptime_count: usize = 0;

    for (__koru_event_input.ast.items) |item| {
        switch (item) {
            .event_decl => |event_decl| {
                // Check if this event has comptime-only parameters
                var is_comptime = false;
                for (event_decl.input.fields) |field| {
                    if (field.is_flow_ast or field.is_source) {
                        is_comptime = true;
                        break;
                    }
                    if (std.mem.eql(u8, field.type, "ProgramAST") or std.mem.eql(u8, field.type, "Program")) {
                        is_comptime = true;
                        break;
                    }
                }

                if (is_comptime and comptime_count < 64) {
                    // Add ALL comptime events (including [norun]) for flow filtering
                    // [norun] just means "don't auto-execute", not "keep flows in runtime"
                    // Build event name from path segments
                    const event_name = joinPath(event_decl.path.segments);
                    comptime_events[comptime_count] = event_name;
                    comptime_count += 1;
                }
            },
            .module_decl => |module| {
                // Also check imported modules
                for (module.items) |mod_item| {
                    if (mod_item == .event_decl) {
                        const event_decl = mod_item.event_decl;
                        var is_comptime = false;
                        for (event_decl.input.fields) |field| {
                            if (field.is_flow_ast or field.is_source) {
                                is_comptime = true;
                                break;
                            }
                            if (std.mem.eql(u8, field.type, "ProgramAST") or std.mem.eql(u8, field.type, "Program")) {
                                is_comptime = true;
                                break;
                            }
                        }

                        if (is_comptime and comptime_count < 64) {
                            const event_name = joinPath(event_decl.path.segments);
                            comptime_events[comptime_count] = event_name;
                            comptime_count += 1;
                        }
                    }
                }
            },
            else => {},
        }
    }

    // Phase 2: Walk flows and find comptime event invocations
    // std.debug.print("  Phase 2: Scanning flows for comptime invocations...\n", .{});
    for (__koru_event_input.ast.items) |item| {
        if (item == .flow) {
            const flow = item.flow;
            const inv_path = joinPath(flow.invocation.path.segments);
            // std.debug.print("    Flow invokes: {s}\n", .{inv_path});

            // Check if this invocation is to a comptime event
            var i: usize = 0;
            while (i < comptime_count) : (i += 1) {
                if (std.mem.eql(u8, inv_path, comptime_events[i])) {
                    // Found a comptime event invocation!
                    // std.debug.print("  ✓ Found comptime invocation: {s}\n", .{inv_path});

                    // Call the comptime handler!
                    const handler_result = callComptimeHandler(inv_path, __koru_event_input.ast);

                    // For now, just print that we called it
                    // TODO: Use result to transform flow/AST
                    switch (handler_result) {
                        .none => {
                            // std.debug.print("  WARNING: Handler not found for: {s}\n", .{inv_path});
                        },
                    }

                    break;
                }
            }
        }
    }

    // std.debug.print("  Detected {} comptime events, {} invocations\n", .{comptime_count, invocations_found});

    // Phase 3: Build new AST without comptime flows and [raw] procs (AST TRANSFORMATION!)
    // Count non-comptime items first
    var count_non_comptime: usize = 0;
    for (__koru_event_input.ast.items) |item| {
        var should_keep = true;
        if (item == .flow) {
            const flow = item.flow;
            const inv_path = joinPath(flow.invocation.path.segments);

            // Check if comptime flow
            for (0..comptime_count) |i| {
                if (std.mem.eql(u8, inv_path, comptime_events[i])) {
                    should_keep = false;
                    break;
                }
            }
        }

        // Filter out [raw] procs that are NOT comptime procs
        if (item == .proc_decl) {
            const proc = item.proc_decl;

            // Check if proc has [raw] annotation
            var has_raw = false;
            for (proc.annotations) |ann| {
                if (std.mem.eql(u8, ann, "raw")) {
                    has_raw = true;
                    break;
                }
            }

            if (has_raw) {
                // Check if this proc is comptime (in comptime_events list)
                const proc_path = joinPath(proc.path.segments);
                var is_comptime = false;
                for (0..comptime_count) |i| {
                    if (std.mem.eql(u8, proc_path, comptime_events[i])) {
                        is_comptime = true;
                        break;
                    }
                }

                // If [raw] but NOT comptime, remove it
                if (!is_comptime) {
                    should_keep = false;
                }
            }
        }

        if (should_keep) {
            count_non_comptime += 1;
        }
    }

    // Build new array with exact size (now allocated at runtime)
    const new_items = try allocator.alloc(Item, count_non_comptime);
    var idx: usize = 0;
    for (__koru_event_input.ast.items) |item| {
        var should_keep = true;
        if (item == .flow) {
            const flow = item.flow;
            const inv_path = joinPath(flow.invocation.path.segments);

            // Check if comptime flow
            for (0..comptime_count) |i| {
                if (std.mem.eql(u8, inv_path, comptime_events[i])) {
                    should_keep = false;
                    break;
                }
            }
        }

        // Filter out [raw] procs that are NOT comptime procs
        if (item == .proc_decl) {
            const proc = item.proc_decl;

            // Check if proc has [raw] annotation
            var has_raw = false;
            for (proc.annotations) |ann| {
                if (std.mem.eql(u8, ann, "raw")) {
                    has_raw = true;
                    break;
                }
            }

            if (has_raw) {
                // Check if this proc is comptime (in comptime_events list)
                const proc_path = joinPath(proc.path.segments);
                var is_comptime = false;
                for (0..comptime_count) |i| {
                    if (std.mem.eql(u8, proc_path, comptime_events[i])) {
                        is_comptime = true;
                        break;
                    }
                }

                // If [raw] but NOT comptime, remove it
                if (!is_comptime) {
                    should_keep = false;
                }
            }
        }

        if (should_keep) {
            new_items[idx] = item;
            idx += 1;
        }
    }

    const transformed_ast = try allocator.create(Program);
    transformed_ast.* = Program{
        .items = new_items,
        .module_annotations = __koru_event_input.ast.module_annotations,
        .main_module_name = __koru_event_input.ast.main_module_name,
        .allocator = allocator,
    };

    return .{ .evaluated = .{
        .ast = transformed_ast,
        .events_executed = 0  // No longer tracked after debug logging removal
    } };
    }
};

const compiler_passes_inject_ccp = struct {
    pub const Input = struct { ast: *const Program, allocator: std.mem.Allocator };
    pub const Output = union(enum) { instrumented: struct { ast: *const Program } };
    pub fn handler(__koru_event_input: Input) !Output {
        const allocator = __koru_event_input.allocator;

    // Inject CCP observability helpers as self-contained Zig code
    // Uses __ccp_std local import to avoid namespace pollution

    // CCP is a self-governing feature that requires BOTH:
    // 1. User imports $std/ccp (declares intent to use CCP)
    // 2. Compiler flag --ccp is set (enables CCP infrastructure)
    // This pattern allows features to exist in AST but remain dormant without flags

    // Check if --ccp flag is set
    if (!CompilerEnv.hasFlag("ccp")) {
        return .{ .instrumented = .{ .ast = __koru_event_input.ast } };
    }

    // Check if $std/ccp was imported (user declared intent)
    var has_ccp_import = false;
    for (__koru_event_input.ast.items) |item| {
        if (item == .import_decl) {
            const imp = item.import_decl;
            // Check if path is exactly "$std/ccp" (user program observability)
            if (std.mem.eql(u8, imp.path, "$std/ccp")) {
                has_ccp_import = true;
                break;
            }
        }
    }

    if (!has_ccp_import) {
        // Flag is set but feature not imported - user didn't declare intent
        return .{ .instrumented = .{ .ast = __koru_event_input.ast } };
    }

    const original_count = __koru_event_input.ast.items.len;
    const new_count = original_count + 1;

    // Create new items array (now allocated at runtime)
    const new_items = try allocator.alloc(Item, new_count);

    // Copy original items
    for (__koru_event_input.ast.items, 0..) |item, i| {
        new_items[i] = item;
    }

    // Inject self-contained CCP helper function
    const ccp_code =
        \\fn __ccp_emit_json(data: anytype) void {
        \\    const __ccp_std = @import("std");
        \\    var buffer: [8192]u8 = undefined;
        \\    var fba = __ccp_std.heap.FixedBufferAllocator.init(&buffer);
        \\    const allocator = fba.allocator();
        \\    var string = __ccp_std.ArrayList(u8).init(allocator);
        \\    defer string.deinit();
        \\    __ccp_std.json.stringify(data, .{}, string.writer()) catch return;
        \\    string.append('\n') catch return;
        \\    const stdout = __ccp_std.io.getStdOut().writer();
        \\    stdout.writeAll(string.items) catch {};
        \\}
    ;

    new_items[original_count] = .{ .host_line = .{
        .content = ccp_code,
        .location = .{ .line = 0, .column = 0, .file = "generated" },
        .module = "ccp_injected"
    } };

    // Create new Program with injected code
    const new_ast = try allocator.create(Program);
    new_ast.* = Program{
        .items = new_items,
        .module_annotations = __koru_event_input.ast.module_annotations,
        .allocator = allocator,
    };

    return .{ .instrumented = .{ .ast = new_ast } };
    }
};

